Here's how to test `DataFetcher` with MSTest, covering success, failure, cancellation, and timeouts:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays forever
        var handler = new FakeHandler(neverCompletes: true);
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // framework cancels after 3s
    public async Task FetchAsync_RespectsTimeout_ViaCancellationToken()
    {
        // Arrange — handler that never responds
        var handler = new FakeHandler(neverCompletes: true);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert — pass TestContext.CancellationToken so the
        // [Timeout] attribute can cancel the call cooperatively
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // Minimal test double for HttpMessageHandler
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly bool _neverCompletes;

        public FakeHandler(HttpResponseMessage response)
            => _response = response;

        public FakeHandler(bool neverCompletes)
            => _neverCompletes = neverCompletes;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_neverCompletes)
            {
                await Task.Delay(Timeout.Infinite, cancellationToken);
            }

            return _response!;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---------|-----|
| `sealed` test class | Performance & design clarity |
| `TestContext` via constructor | Gives access to `CancellationToken` |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — the framework signals cancellation instead of hard-aborting the thread |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]`; lets you inspect the exception |
| `FakeHandler` | Avoids mocking frameworks; gives full control over `HttpClient` behavior |

The critical insight: always pass `TestContext.CancellationToken` into your async calls when using `[Timeout]`. Without it, the timeout can't cooperatively cancel the operation.
